exec("""\n#!/usr/bin/env python3\n# -*- coding: utf-8 -*-\n\"\"\"\nPAQJP 8.2 – FULLY LOSSLESS EDITION (256 TRANSFORMS: 0‑255)\nAll transforms (0‑255) are 100% reversible for every byte value 0‑255.\nTransform 255 is the identity transform (no change) – no separate raw fallback.\n\nBUG FIXES (final):\n  - _rle_decode now checks exact bit requirements for each run code → no more\n    “out of bits” errors on long runs.\n  - Ratio calculation for empty files no longer divides by zero.\n  - File open errors are caught and reported to the user.\n  - All transforms have been verified through the self‑test.\n\nNo emoji/icons – uses plain ASCII.\n\"\"\"\n\nimport math\nimport random\nfrom typing import Optional, List\n\n# Optional compression backends\ntry:\n    import paq\nexcept ImportError:\n    paq = None\n\ntry:\n    import zstandard as zstd\n    zstd_cctx = zstd.ZstdCompressor(level=22)\n    zstd_dctx = zstd.ZstdDecompressor()\n    HAS_ZSTD = True\nexcept ImportError:\n    HAS_ZSTD = False\n\nPROGNAME = "PAQJP_8.2_LOSSLESS_256_TRANSFORMS"\n\nPRIMES = [p for p in range(2, 256) if all(p % d != 0 for d in range(2, int(p**0.5)+1))]\nPI_DIGITS = [79, 17, 111]\n\n\ndef find_nearest_prime_around(n: int) -> int:\n    o = 0\n    while True:\n        c1, c2 = n - o, n + o\n        if c1 >= 2 and all(c1 % d != 0 for d in range(2, int(c1**0.5)+1)):\n            return c1\n        if c2 >= 2 and all(c2 % d != 0 for d in range(2, int(c2**0.5)+1)):\n            return c2\n        o += 1\n\n\nclass PAQJPCompressor:\n    def __init__(self):\n        self.PI_DIGITS = PI_DIGITS.copy()\n        self.seed_tables = self._gen_seed_tables()\n        self.fibonacci = self._gen_fib(100)\n\n    def _gen_fib(self, n):\n        a, b = 0, 1\n        res = [a, b]\n        for _ in range(2, n):\n            a, b = b, a + b\n            res.append(b)\n        return res\n\n    def _gen_seed_tables(self, num=126, size=256, seed=42):\n        random.seed(seed)\n        return [[random.randint(5, 255) for _ in range(size)] for _ in range(num)]\n\n    def get_seed(self, idx: int, val: int) -> int:\n        if 0 <= idx < len(self.seed_tables):\n            return self.seed_tables[idx][val % 256]\n        return 0\n\n    # ------------------------------------------------------------------\n    # Bit helpers\n    # ------------------------------------------------------------------\n    def _append_bits(self, bitlist: List[int], value: int, count: int):\n        for i in range(count - 1, -1, -1):\n            bitlist.append((value >> i) & 1)\n\n    def _read_bits(self, bits: List[int], pos: int, count: int) -> int:\n        val = 0\n        for i in range(count):\n            if pos + i >= len(bits):\n                return 0\n            val = (val << 1) | bits[pos + i]\n        return val\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 00 – multi‑pass shift + compact RLE (FULLY LOSSLESS)\n    # ------------------------------------------------------------------\n    def transform_00(self, data: bytes) -> bytes:\n        if not data:\n            return b'\\x00'\n\n        best_result = None\n        best_length = float('inf')\n        best_shifts = []\n        MAX_PASSES = 10\n\n        current = bytearray(data)\n        applied_shifts = []\n\n        for _ in range(MAX_PASSES):\n            best_shift = 0\n            best_shifted = current\n            best_score = float('-inf')\n\n            for shift in range(256):\n                tmp = bytearray(current)\n                for j in range(len(tmp)):\n                    tmp[j] = (tmp[j] + shift) % 256\n\n                score = 0\n                i = 0\n                while i < len(tmp):\n                    val = tmp[i]\n                    run = 1\n                    i += 1\n                    while i < len(tmp) and tmp[i] == val:\n                        run += 1\n                        i += 1\n                    score += run * run\n\n                if score > best_score:\n                    best_score = score\n                    best_shifted = tmp\n                    best_shift = shift\n\n            applied_shifts.append(best_shift)\n            rle_encoded = self._apply_rle_to_shifted(best_shifted, best_shift)\n\n            if len(rle_encoded) < best_length:\n                best_length = len(rle_encoded)\n                best_result = rle_encoded\n                best_shifts = applied_shifts.copy()\n\n            current = best_shifted\n            if len(rle_encoded) >= len(data):\n                break\n\n        if best_result is None or best_length >= len(data):\n            return bytes([0]) + data\n\n        header = bytearray([len(best_shifts)])\n        header.extend(best_shifts)\n        return header + best_result\n\n    def _apply_rle_to_shifted(self, shifted_data: bytearray, shift: int) -> bytes:\n        bits = []\n        self._append_bits(bits, 0b010, 3)\n        self._append_bits(bits, shift, 8)\n\n        i = 0\n        n = len(shifted_data)\n        while i < n:\n            val = shifted_data[i]\n            run = 1\n            i += 1\n            while i < n and shifted_data[i] == val:\n                run += 1\n                i += 1\n\n            while run >= 13:\n                chunk = min(run, 268)\n                self._append_bits(bits, 0b1111, 4)\n                self._append_bits(bits, chunk - 13, 8)\n                self._append_bits(bits, val, 8)\n                run -= chunk\n\n            if run == 1:\n                self._append_bits(bits, 0b00, 2)\n                self._append_bits(bits, val, 8)\n            elif run <= 5:\n                self._append_bits(bits, 0b01, 2)\n                self._append_bits(bits, run - 2, 2)\n                self._append_bits(bits, val, 8)\n            elif run <= 12:\n                self._append_bits(bits, 0b10, 2)\n                self._append_bits(bits, run - 6, 3)\n                self._append_bits(bits, val, 8)\n\n        pad = (8 - len(bits) % 8) % 8\n        self._append_bits(bits, 0, pad)\n\n        out = bytearray()\n        for j in range(0, len(bits), 8):\n            byte = 0\n            for k in range(8):\n                if j + k < len(bits):\n                    byte = (byte << 1) | bits[j + k]\n            out.append(byte)\n        return bytes(out)\n\n    def reverse_transform_00(self, cdata: bytes) -> bytes:\n        if not cdata or cdata == b'\\x00':\n            return b''\n        if cdata[0] == 0:\n            return cdata[1:]\n\n        num_passes = cdata[0]\n        if num_passes == 0 or len(cdata) < 1 + num_passes:\n            return b''\n\n        shifts = list(cdata[1:1 + num_passes])\n        rle_data = cdata[1 + num_passes:]\n\n        decoded = self._rle_decode(rle_data)\n        if decoded is None:\n            return b''\n\n        current = bytearray(decoded)\n        for shift in reversed(shifts):\n            for i in range(len(current)):\n                current[i] = (current[i] - shift) % 256\n        return bytes(current)\n\n    def _rle_decode(self, data: bytes) -> Optional[bytearray]:\n        \"\"\"Fully fixed bit‑accurate RLE decoder.\"\"\"\n        if not data:\n            return None\n        bits = []\n        for b in data:\n            for i in range(7, -1, -1):\n                bits.append((b >> i) & 1)\n\n        pos = 0\n        nbits = len(bits)\n        if nbits < 11:\n            return None\n\n        # read and verify marker\n        marker = self._read_bits(bits, pos, 3)\n        pos += 3\n        if marker != 0b010:\n            return None\n        # skip shift (8 bits) – it is stored but not needed for decode\n        pos += 8\n\n        out = bytearray()\n        while pos < nbits:\n            # need at least 2 bits for prefix\n            if pos + 2 > nbits:\n                break\n            prefix = self._read_bits(bits, pos, 2)\n            pos += 2\n\n            if prefix == 0b00:\n                # run = 1, then 8 bits value\n                if pos + 8 > nbits:\n                    break\n                run = 1\n            elif prefix == 0b01:\n                # run = 2 + next 2 bits, then 8 bits value\n                if pos + 2 + 8 > nbits:\n                    break\n                run = 2 + self._read_bits(bits, pos, 2)\n                pos += 2\n            elif prefix == 0b10:\n                # run = 6 + next 3 bits, then 8 bits value\n                if pos + 3 + 8 > nbits:\n                    break\n                run = 6 + self._read_bits(bits, pos, 3)\n                pos += 3\n            else:  # prefix == 0b11\n                # long run: next 2 bits must be 11, then 8 bits run-13, then 8 bits value\n                if pos + 2 + 8 + 8 > nbits:\n                    break\n                if self._read_bits(bits, pos, 2) != 0b11:\n                    return None\n                pos += 2\n                run = 13 + self._read_bits(bits, pos, 8)\n                pos += 8\n\n            # read value byte\n            if pos + 8 > nbits:\n                break\n            val = self._read_bits(bits, pos, 8)\n            pos += 8\n\n            out.extend([val] * run)\n\n        # all remaining bits must be zero (padding)\n        for i in range(pos, nbits):\n            if bits[i] != 0:\n                return None\n        return out\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 01 – involutory XOR (lossless)\n    # ------------------------------------------------------------------\n    def transform_01(self, d, r=100):\n        t = bytearray(d)\n        for prime in PRIMES:\n            xor_val = prime if prime == 2 else max(1, math.ceil(prime * 4096 / 28672))\n            for _ in range(r):\n                for i in range(0, len(t), 3):\n                    if i < len(t):\n                        t[i] ^= xor_val\n        return bytes(t)\n\n    def reverse_transform_01(self, d, r=100):\n        return self.transform_01(d, r)\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 02 – FIXED: use stored pattern index\n    # ------------------------------------------------------------------\n    def transform_02(self, d):\n        if len(d) < 1:\n            return b''\n        t = bytearray(d)\n        checksum = sum(d) % 256\n        pattern_index = (len(d) + checksum) % 256\n        pattern_values = self._get_pattern(4, pattern_index)\n        for i in range(1, len(t), 4):\n            if i < len(t):\n                t[i] ^= pattern_values[i % len(pattern_values)]\n        return bytes([pattern_index]) + bytes(t)\n\n    def reverse_transform_02(self, d):\n        if len(d) < 2:\n            return b''\n        pattern_index = d[0]\n        t = bytearray(d[1:])\n        pattern_values = self._get_pattern(4, pattern_index)\n        for i in range(1, len(t), 4):\n            if i < len(t):\n                t[i] ^= pattern_values[i % len(pattern_values)]\n        return bytes(t)\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 03 – rotate bits (lossless)\n    # ------------------------------------------------------------------\n    def transform_03(self, d):\n        if len(d) < 1:\n            return b''\n        t = bytearray(d)\n        rotation = (len(d) * 13 + sum(d)) % 8\n        if rotation == 0:\n            rotation = 1\n        for i in range(2, len(t), 5):\n            if i < len(t):\n                t[i] = ((t[i] << rotation) | (t[i] >> (8 - rotation))) & 0xFF\n        return bytes([rotation]) + bytes(t)\n\n    def reverse_transform_03(self, d):\n        if len(d) < 2:\n            return b''\n        rotation = d[0]\n        t = bytearray(d[1:])\n        for i in range(2, len(t), 5):\n            if i < len(t):\n                t[i] = ((t[i] >> rotation) | (t[i] << (8 - rotation))) & 0xFF\n        return bytes(t)\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 04 – subtract/add i%256 (lossless)\n    # ------------------------------------------------------------------\n    def transform_04(self, d, r=100):\n        t = bytearray(d)\n        for _ in range(r):\n            for i in range(len(t)):\n                t[i] = (t[i] - (i % 256)) % 256\n        return bytes(t)\n\n    def reverse_transform_04(self, d, r=100):\n        t = bytearray(d)\n        for _ in range(r):\n            for i in range(len(t)):\n                t[i] = (t[i] + (i % 256)) % 256\n        return bytes(t)\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 05 – rotate each byte (lossless)\n    # ------------------------------------------------------------------\n    def transform_05(self, d, s=3):\n        t = bytearray(d)\n        for i in range(len(t)):\n            t[i] = ((t[i] << s) | (t[i] >> (8 - s))) & 0xFF\n        return bytes(t)\n\n    def reverse_transform_05(self, d, s=3):\n        t = bytearray(d)\n        for i in range(len(t)):\n            t[i] = ((t[i] >> s) | (t[i] << (8 - s))) & 0xFF\n        return bytes(t)\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 06 – substitution cipher (lossless)\n    # ------------------------------------------------------------------\n    def transform_06(self, d, sd=42):\n        random.seed(sd)\n        sub = list(range(256))\n        random.shuffle(sub)\n        t = bytearray(d)\n        for i in range(len(t)):\n            t[i] = sub[t[i]]\n        return bytes(t)\n\n    def reverse_transform_06(self, d, sd=42):\n        random.seed(sd)\n        sub = list(range(256))\n        random.shuffle(sub)\n        inv = [0] * 256\n        for i in range(256):\n            inv[sub[i]] = i\n        t = bytearray(d)\n        for i in range(len(t)):\n            t[i] = inv[t[i]]\n        return bytes(t)\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 07 – XOR with length + pi (involutory)\n    # ------------------------------------------------------------------\n    def transform_07(self, d, r=100):\n        t = bytearray(d)\n        sh = len(d) % len(self.PI_DIGITS)\n        pi_rot = self.PI_DIGITS[sh:] + self.PI_DIGITS[:sh]\n        sz = len(d) % 256\n        for i in range(len(t)):\n            t[i] ^= sz\n        for _ in range(r):\n            for i in range(len(t)):\n                t[i] ^= pi_rot[i % len(pi_rot)]\n        return bytes(t)\n\n    def reverse_transform_07(self, d, r=100):\n        return self.transform_07(d, r)\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 08 – XOR with prime + pi (involutory)\n    # ------------------------------------------------------------------\n    def transform_08(self, d, r=100):\n        t = bytearray(d)\n        sh = len(d) % len(self.PI_DIGITS)\n        pi_rot = self.PI_DIGITS[sh:] + self.PI_DIGITS[:sh]\n        p = find_nearest_prime_around(len(d) % 256)\n        for i in range(len(t)):\n            t[i] ^= p\n        for _ in range(r):\n            for i in range(len(t)):\n                t[i] ^= pi_rot[i % len(pi_rot)]\n        return bytes(t)\n\n    def reverse_transform_08(self, d, r=100):\n        return self.transform_08(d, r)\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 09 – XOR with prime, seed, pi, i (involutory)\n    # ------------------------------------------------------------------\n    def transform_09(self, d, r=100):\n        t = bytearray(d)\n        sh = len(d) % len(self.PI_DIGITS)\n        pi_rot = self.PI_DIGITS[sh:] + self.PI_DIGITS[:sh]\n        p = find_nearest_prime_around(len(d) % 256)\n        seed = self.get_seed(len(d) % len(self.seed_tables), len(d))\n        for i in range(len(t)):\n            t[i] ^= p ^ seed\n        for _ in range(r):\n            for i in range(len(t)):\n                t[i] ^= pi_rot[i % len(pi_rot)] ^ (i % 256)\n        return bytes(t)\n\n    def reverse_transform_09(self, d, r=100):\n        return self.transform_09(d, r)\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 10 – XOR with n from "X1" count (involutory)\n    # ------------------------------------------------------------------\n    def transform_10(self, d, r=100):\n        cnt = sum(1 for i in range(len(d) - 1) if d[i:i + 2] == b'X1')\n        n = (((cnt * 2) + 1) // 3) * 3 % 256\n        t = bytearray(d)\n        for _ in range(r):\n            for i in range(len(t)):\n                t[i] ^= n\n        return bytes([n]) + bytes(t)\n\n    def reverse_transform_10(self, d, r=100):\n        if len(d) < 1:\n            return b''\n        n = d[0]\n        t = bytearray(d[1:])\n        for _ in range(r):\n            for i in range(len(t)):\n                t[i] ^= n\n        return bytes(t)\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 11 – FIXED: reverse order\n    # ------------------------------------------------------------------\n    def transform_11(self, d, r=100):\n        if not d:\n            return b''\n        t = bytearray(d)\n        length = len(t)\n        for _ in range(r):\n            for i in range(length):\n                fib_idx = (i + length) % len(self.fibonacci)\n                fib_val = self.fibonacci[fib_idx] % 256\n                pos_val = (i * 13 + length * 17) % 256\n                prev_val = t[i - 1] if i > 0 else length % 256\n                t[i] = (t[i] ^ fib_val ^ pos_val ^ prev_val) % 256\n        return bytes(t)\n\n    def reverse_transform_11(self, d, r=100):\n        if not d:\n            return b''\n        t = bytearray(d)\n        length = len(t)\n        for _ in range(r):\n            for i in range(length - 1, -1, -1):\n                fib_idx = (i + length) % len(self.fibonacci)\n                fib_val = self.fibonacci[fib_idx] % 256\n                pos_val = (i * 13 + length * 17) % 256\n                prev_val = t[i - 1] if i > 0 else length % 256\n                t[i] = (t[i] ^ fib_val ^ pos_val ^ prev_val) % 256\n        return bytes(t)\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 12 – XOR with Fibonacci (involutory)\n    # ------------------------------------------------------------------\n    def transform_12(self, d, r=100):\n        t = bytearray(d)\n        for _ in range(r):\n            for i in range(len(t)):\n                t[i] ^= self.fibonacci[i % len(self.fibonacci)] % 256\n        return bytes(t)\n\n    def reverse_transform_12(self, d, r=100):\n        return self.transform_12(d, r)\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 13 – XOR with nearest prime (lossless)\n    # ------------------------------------------------------------------\n    def transform_13(self, d):\n        if not d:\n            return b''\n        repeats = self._calculate_repeats(d)\n        current_value = len(d) % 256\n        prime_values = []\n        count = 0\n        while count < repeats:\n            current_value = find_nearest_prime_around(current_value)\n            prime_values.append(current_value)\n            count += 1\n        t = bytearray(d)\n        xor_value = prime_values[-1] if prime_values else 0\n        for i in range(len(t)):\n            t[i] ^= xor_value\n        repeat_byte = (repeats - 1) % 256\n        return bytes([repeat_byte]) + bytes(t)\n\n    def reverse_transform_13(self, d):\n        if len(d) < 2:\n            return b''\n        repeat_byte = d[0]\n        repeats = (repeat_byte + 1) % 256\n        if repeats == 0:\n            repeats = 256\n        t = bytearray(d[1:])\n        current_value = len(t) % 256\n        prime_values = []\n        count = 0\n        while count < repeats:\n            current_value = find_nearest_prime_around(current_value)\n            prime_values.append(current_value)\n            count += 1\n        xor_value = prime_values[-1] if prime_values else 0\n        for i in range(len(t)):\n            t[i] ^= xor_value\n        return bytes(t)\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 14 – FIXED: ALWAYS prepend bits_to_add byte\n    # ------------------------------------------------------------------\n    def transform_14(self, d):\n        if not d:\n            return b'\\x00'  # marker for empty data (reversible)\n        bits_to_add = self._calculate_bits_to_add(d)\n        transformed = self._add_bits_to_end(d, bits_to_add)\n        return bytes([bits_to_add]) + transformed\n\n    def reverse_transform_14(self, d):\n        if len(d) < 1:\n            return b''\n        bits_count = d[0]\n        data_with_bits = d[1:]\n        if not data_with_bits:\n            return b''\n        # Remove the appended metadata byte (always present)\n        return data_with_bits[:-1]\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 15 – add pattern to every 3rd byte (lossless)\n    # ------------------------------------------------------------------\n    def transform_15(self, d):\n        if len(d) < 1:\n            return b''\n        t = bytearray(d)\n        pattern_index = len(d) % 256\n        pattern_values = self._get_pattern(3, pattern_index)\n        for i in range(0, len(t), 3):\n            if i < len(t):\n                t[i] = (t[i] + pattern_values[i % len(pattern_values)]) % 256\n        return bytes([pattern_index]) + bytes(t)\n\n    def reverse_transform_15(self, d):\n        if len(d) < 2:\n            return b''\n        pattern_index = d[0]\n        t = bytearray(d[1:])\n        pattern_values = self._get_pattern(3, pattern_index)\n        for i in range(0, len(t), 3):\n            if i < len(t):\n                t[i] = (t[i] - pattern_values[i % len(pattern_values)]) % 256\n        return bytes(t)\n\n    # ------------------------------------------------------------------\n    # TRANSFORM 255 – Identity (lossless, no change)\n    # ------------------------------------------------------------------\n    def transform_255(self, d: bytes) -> bytes:\n        return d\n\n    def reverse_transform_255(self, d: bytes) -> bytes:\n        return d\n\n    # ------------------------------------------------------------------\n    # Helpers for transforms 13,14,15\n    # ------------------------------------------------------------------\n    def _calculate_bits_to_add(self, data: bytes) -> int:\n        if not data:\n            return 0\n        length = len(data)\n        first = data[0]\n        last = data[-1]\n        checksum = sum(data) % 256\n        return ((length * 13 + first * 17 + last * 23 + checksum * 29) % 9)\n\n    def _add_bits_to_end(self, data: bytes, bits_count: int) -> bytes:\n        if bits_count == 0:\n            return data + b'\\x00'\n        if not data:\n            data = b'\\x00'\n        last_byte = data[-1]\n        bits_value = last_byte & ((1 << bits_count) - 1)\n        bits_byte = ((bits_count & 0x0F) << 4) | (bits_value & 0x0F)\n        return data + bytes([bits_byte])\n\n    def _get_pattern(self, size: int, index: int):\n        random.seed(12345 + size * 100 + index)\n        return [random.randint(0, 255) for _ in range(size)]\n\n    def _calculate_repeats(self, data: bytes) -> int:\n        if not data:\n            return 1\n        length = len(data)\n        byte_sum = sum(data) % 256\n        repeats = ((length * 13 + byte_sum * 17) % 256) + 1\n        return max(1, min(256, repeats))\n\n    # ------------------------------------------------------------------\n    # Dynamic transforms 16‑254 – XOR with seed (involutory, lossless)\n    # (Marker 255 is identity – see above)\n    # ------------------------------------------------------------------\n    def _dynamic_transform(self, n: int):\n        def tf(data: bytes):\n            if not data:\n                return b''\n            seed = self.get_seed(n % len(self.seed_tables), len(data))\n            t = bytearray(data)\n            for i in range(len(t)):\n                t[i] ^= seed\n            return bytes(t)\n        return tf, tf\n\n    # ------------------------------------------------------------------\n    # Compression backends – with raw fallback\n    # ------------------------------------------------------------------\n    def _compress_backend(self, data: bytes) -> bytes:\n        candidates = []\n        if paq is not None:\n            try:\n                candidates.append((b'L', paq.compress(data)))\n            except:\n                pass\n        if HAS_ZSTD:\n            try:\n                candidates.append((b'Z', zstd_cctx.compress(data)))\n            except:\n                pass\n\n        if not candidates:\n            return b'N' + data\n\n        winner_id, winner_data = min(candidates, key=lambda x: len(x[1]))\n        return winner_id + winner_data\n\n    def _decompress_backend(self, data: bytes) -> Optional[bytes]:\n        if len(data) < 1:\n            return None\n        engine = data[0]\n        payload = data[1:]\n\n        if engine == ord('L') and paq is not None:\n            try:\n                return paq.decompress(payload)\n            except:\n                return None\n        if engine == ord('Z') and HAS_ZSTD:\n            try:\n                return zstd_dctx.decompress(payload)\n            except:\n                return None\n        if engine == ord('N'):\n            return payload\n        return None\n\n    # ------------------------------------------------------------------\n    # FULL self‑test – verifies EVERY transform 0‑255 and full pipeline\n    # ------------------------------------------------------------------\n    def self_test(self) -> bool:\n        print("Running FULL self‑test to verify ALL transforms (0‑255) are lossless...")\n        test_passed = True\n\n        transforms = [\n            (0, self.transform_00, self.reverse_transform_00),\n            (1, self.transform_01, self.reverse_transform_01),\n            (2, self.transform_02, self.reverse_transform_02),\n            (3, self.transform_03, self.reverse_transform_03),\n            (4, self.transform_04, self.reverse_transform_04),\n            (5, self.transform_05, self.reverse_transform_05),\n            (6, self.transform_06, self.reverse_transform_06),\n            (7, self.transform_07, self.reverse_transform_07),\n            (8, self.transform_08, self.reverse_transform_08),\n            (9, self.transform_09, self.reverse_transform_09),\n            (10, self.transform_10, self.reverse_transform_10),\n            (11, self.transform_11, self.reverse_transform_11),\n            (12, self.transform_12, self.reverse_transform_12),\n            (13, self.transform_13, self.reverse_transform_13),\n            (14, self.transform_14, self.reverse_transform_14),\n            (15, self.transform_15, self.reverse_transform_15),\n        ]\n        for i in range(16, 255):\n            fwd, rev = self._dynamic_transform(i)\n            transforms.append((i, fwd, rev))\n        transforms.append((255, self.transform_255, self.reverse_transform_255))\n\n        print(f"  Testing {len(transforms)} transforms (0‑255)...")\n\n        # --- Test empty data (skip transform 00 because it returns b'\\x00' and expects that) ---\n        for num, fwd, rev in transforms:\n            if num == 0:\n                continue\n            try:\n                enc = fwd(b'')\n                dec = rev(enc)\n                if dec != b'':\n                    print(f"  [FAIL] Transform {num} empty data")\n                    test_passed = False\n            except Exception:\n                print(f"  [FAIL] Transform {num} empty data (exception)")\n                test_passed = False\n\n        # --- Test all 256 single bytes for every transform ---\n        for num, fwd, rev in transforms:\n            for b_val in range(256):\n                orig = bytes([b_val])\n                try:\n                    enc = fwd(orig)\n                    dec = rev(enc)\n                except Exception:\n                    print(f"  [FAIL] Transform {num} byte 0x{b_val:02x} (exception)")\n                    test_passed = False\n                    break\n                if dec != orig:\n                    print(f"  [FAIL] Transform {num} byte 0x{b_val:02x}")\n                    test_passed = False\n                    break\n            else:\n                if num <= 15 or num % 50 == 0 or num == 255:\n                    print(f"  [PASS] Transform {num} all single bytes")\n\n        # --- Test random short data (5 samples per transform) ---\n        random.seed(123)\n        for num, fwd, rev in transforms:\n            for sample in range(5):\n                size = random.randint(1, 100)\n                data = bytes(random.getrandbits(8) for _ in range(size))\n                try:\n                    enc = fwd(data)\n                    dec = rev(enc)\n                except Exception:\n                    print(f"  [FAIL] Transform {num} random size {size} (exception)")\n                    test_passed = False\n                    break\n                if dec != data:\n                    print(f"  [FAIL] Transform {num} random size {size}")\n                    test_passed = False\n                    break\n            else:\n                if num <= 15 or num % 50 == 0 or num == 255:\n                    print(f"  [PASS] Transform {num} random short data")\n\n        # --- Full pipeline test (100 random inputs) ---\n        print("\\n  Testing full compression/decompression pipeline on random data...")\n        random.seed(456)\n        for test_num in range(100):\n            size = random.randint(1, 500)\n            data = bytes(random.getrandbits(8) for _ in range(size))\n            try:\n                compressed = self.compress_with_best(data)\n                decompressed, marker = self.decompress_with_best(compressed)\n            except Exception:\n                print(f"  [FAIL] Pipeline test #{test_num+1} (exception)")\n                test_passed = False\n                break\n            if decompressed != data:\n                print(f"  [FAIL] Pipeline test #{test_num+1} (marker {marker})")\n                test_passed = False\n                break\n        else:\n            print("  [PASS] Full pipeline (100 random inputs)")\n\n        if test_passed:\n            print("\\n[PASS] Self‑test PASSED – all transforms 0‑255 are 100% lossless.\\n")\n        else:\n            print("\\n[FAIL] Self‑test FAILED – please report this bug!\\n")\n        return test_passed\n\n    # ------------------------------------------------------------------\n    # Main compression logic – tries ALL transforms 0‑255\n    # (Marker 255 is the identity transform – no separate raw fallback)\n    # ------------------------------------------------------------------\n    def compress_with_best(self, data: bytes) -> bytes:\n        if not data:\n            return bytes([255]) + self._compress_backend(b'')\n\n        best_payload = None\n        best_size = float('inf')\n        best_marker = 255  # identity fallback\n\n        transforms = [\n            (0,   self.transform_00),\n            (1,   self.transform_01),\n            (2,   self.transform_02),\n            (3,   self.transform_03),\n            (4,   self.transform_04),\n            (5,   self.transform_05),\n            (6,   self.transform_06),\n            (7,   self.transform_07),\n            (8,   self.transform_08),\n            (9,   self.transform_09),\n            (10,  self.transform_10),\n            (11,  self.transform_11),\n            (12,  self.transform_12),\n            (13,  self.transform_13),\n            (14,  self.transform_14),\n            (15,  self.transform_15),\n        ] + [(i, self._dynamic_transform(i)[0]) for i in range(16, 255)] + \\\n          [(255, self.transform_255)]\n\n        for marker, func in transforms:\n            try:\n                transformed = func(data)\n                compressed = self._compress_backend(transformed)\n                clen = len(compressed)\n                if clen < best_size:\n                    best_size = clen\n                    best_payload = compressed\n                    best_marker = marker\n            except Exception:\n                continue\n\n        return bytes([best_marker]) + best_payload\n\n    def decompress_with_best(self, data: bytes):\n        if len(data) < 2:\n            return b'', None\n\n        marker = data[0]\n        payload = data[1:]\n\n        backend = self._decompress_backend(payload)\n        if backend is None:\n            return b'', None\n\n        rev_map = {\n            0:    self.reverse_transform_00,\n            1:    self.reverse_transform_01,\n            2:    self.reverse_transform_02,\n            3:    self.reverse_transform_03,\n            4:    self.reverse_transform_04,\n            5:    self.reverse_transform_05,\n            6:    self.reverse_transform_06,\n            7:    self.reverse_transform_07,\n            8:    self.reverse_transform_08,\n            9:    self.reverse_transform_09,\n            10:   self.reverse_transform_10,\n            11:   self.reverse_transform_11,\n            12:   self.reverse_transform_12,\n            13:   self.reverse_transform_13,\n            14:   self.reverse_transform_14,\n            15:   self.reverse_transform_15,\n        }\n        for i in range(16, 255):\n            rev_map[i] = self._dynamic_transform(i)[1]\n        rev_map[255] = self.reverse_transform_255\n\n        rev_func = rev_map.get(marker, lambda x: x)\n        try:\n            result = rev_func(backend)\n        except Exception:\n            return b'', None\n        return result, marker\n\n    # ------------------------------------------------------------------\n    # Public file API – with proper error handling\n    # ------------------------------------------------------------------\n    def compress(self, infile: str, outfile: str):\n        try:\n            with open(infile, 'rb') as f:\n                data = f.read()\n        except FileNotFoundError:\n            print(f"Error: input file '{infile}' not found.")\n            return\n        except Exception as e:\n            print(f"Error reading file: {e}")\n            return\n\n        compressed = self.compress_with_best(data)\n\n        try:\n            with open(outfile, 'wb') as f:\n                f.write(compressed)\n        except Exception as e:\n            print(f"Error writing output file: {e}")\n            return\n\n        if len(data) == 0:\n            print(f"Compressed empty file -> {outfile} (0 bytes)")\n        else:\n            ratio = (1 - len(compressed) / len(data)) * 100\n            if paq is None and not HAS_ZSTD:\n                backend_info = " (no compression backend - raw storage used)"\n            elif HAS_ZSTD:\n                backend_info = " (zstd)"\n            else:\n                backend_info = " (paq only)"\n            print(f"Compressed {len(data)} -> {len(compressed)} bytes ({ratio:.2f}% saved){backend_info} -> {outfile}")\n\n    def decompress(self, infile: str, outfile: str):\n        try:\n            with open(infile, 'rb') as f:\n                data = f.read()\n        except FileNotFoundError:\n            print(f"Error: compressed file '{infile}' not found.")\n            return\n        except Exception as e:\n            print(f"Error reading file: {e}")\n            return\n\n        original, marker = self.decompress_with_best(data)\n        if original is None or original == b'':\n            print("Decompression failed: invalid compressed data or transform error.")\n            return\n\n        try:\n            with open(outfile, 'wb') as f:\n                f.write(original)\n        except Exception as e:\n            print(f"Error writing output file: {e}")\n            return\n\n        print(f"Decompressed (transform {marker}) -> {outfile} ({len(original)} bytes)")\n\n\ndef main():\n    print(f"{PROGNAME} - fully lossless, all transforms 0‑255 verified")\n    c = PAQJPCompressor()\n\n    ch = input("1) Compress   2) Decompress   3) Verify all transforms\\n> ").strip()\n    if ch == "1":\n        i = input("Input file: ").strip()\n        o = input("Output file: ").strip() or i + ".pjp"\n        c.compress(i, o)\n    elif ch == "2":\n        i = input("Compressed file: ").strip()\n        o = input("Output file: ").strip() or i.rsplit('.', 1)[0] + ".orig"\n        c.decompress(i, o)\n    elif ch == "3":\n        c.self_test()\n    else:\n        print("Invalid choice.")\n\n\nif __name__ == "__main__":\n    main()\n""")
